button_iadd.script:
function onButtonPress()
	if not Session.IsHost then
		CrewManager.sendPlayerCreateClockOobMsg()
		return;
	end
	super.onButtonPress();
end

windowclass.script:
function onInit()
	if Session.IsHost then
		return;
	end

	registerMenuItem(Interface.getString("list_menu_deleteitem"), "delete", 6);
	registerMenuItem(Interface.getString("list_menu_deleteconfirm"), "delete", 6, 7);
end

function onMenuSelection(selection, subselection)
	if not Session.IsHost then
		if selection == 6 and subselection == 7 then
			CrewManager.sendPlayerDeleteClockOobMsg(getDatabaseNode());
		end
	end
end

comboboxc_content_top_sizeselector.script:
function setControlValue(nValue)
	if Session.IsHost then
		super.setControlValue(nValue);
		return;
	end
	local sPath = DB.getPath(window.getDatabaseNode(), "size");
	CrewManager.sendPlayerUpdateOobMsg(sPath, "number", nValue);
end

button_content_top_clock.script:
function setSizeValue(n)
	if Session.IsHost then
		super.setSizeValue(n);
		return;
	end

	CrewManager.sendPlayerUpdateOobMsg(self.getSizeNodeName(), "number", n);
end

function setCurrentValue(n)
	if Session.IsHost then
		super.setCurrentValue(n);
		return;
	end

	CrewManager.sendPlayerUpdateOobMsg(self.getCurrentNodeName(), "number", n);
end
